INSERT INTO `kiusc_notice_board` (`id`, `dep_id`, `prog_id`, `stud_id`, `msg_date`, `exp_date`, `title`, `detail`) VALUES
(5, -1, -1, -1, '2016-06-20', '2016-06-22', 'Fee Reimbursement Scheme', ' All Students of Masters Programs are hereby informed to validate their data in HEC Web site (pmfrsc.hec.govt.com up to April, 21 2016 and new students 2016 to validate their data up to April, 30 2016. Those students who will not validate their data within the deadline will be responsible to pay their semester fees. This is the last chance for the students as informed to the HEC. The list of not validate students are already on notice board.\r\n\r\nCoordinator Academics KIU Skardu Campus'),
(6, -1, -1, -1, '2016-06-20', '2016-06-30', 'Final Term Exam', ' All Students are informed that final term examination will start from 20th June, 2016.');
