(1, 55, 'Add Course', 'add-course', '<p>Add Course</p>\r\n<p>{source}</p>\r\n<p>&lt;?php</p>\r\n<p style="font-size: 12.1599998474121px; line-height: 15.8079996109009px;">Â //require_once("myfiles/courses/courses.php");</p>\r\n<p style="font-size: 12.1599998474121px; line-height: 15.8079996109009px;"><span style="font-family: ''Fira Mono'', ''Source Code Pro'', monospace; font-size: 14px; line-height: 24px; color: #007700;">include </span><span style="font-family: ''Fira Mono'', ''Source Code Pro'', monospace; font-size: 14px; line-height: 24px;"><span style="color: #dd0000;">"</span></span><span style="font-size: 12.1599998474121px; line-height: 15.8079996109009px;">myfiles/courses/courses.php<span style="color: #dd0000;">"</span></span><span style="font-family: ''Fira Mono'', ''Source Code Pro'', monospace; font-size: 14px; line-height: 24px; color: #007700;">;</span></p>\r\n<p>start();</p>\r\n<p>?&gt;</p>\r\n<p>{/source}</p>', '', 1, 2, '2015-02-09 11:23:10', 245, '', '2014-11-08 09:15:05', 245, 245, '2015-06-26 01:19:43', '2014-11-08 09:15:05', '0000-00-00 00:00:00', '{"image_intro":"","float_intro":"","image_intro_alt":"","image_intro_caption":"","image_fulltext":"","float_fulltext":"","image_fulltext_alt":"","image_fulltext_caption":""}', '{"urla":false,"urlatext":"","targeta":"","urlb":false,"urlbtext":"","targetb":"","urlc":false,"urlctext":"","targetc":""}', '{"show_title":"","link_titles":"","show_tags":"","show_intro":"","info_block_position":"","show_category":"","link_category":"","show_parent_category":"","link_parent_category":"","show_author":"","link_author":"","show_create_date":"","show_modify_date":"","show_publish_date":"","show_item_navigation":"","show_icons":"","show_print_icon":"","show_email_icon":"","show_vote":"","show_hits":"","show_noauth":"","urls_position":"","alternative_readmore":"","article_layout":"","show_publishing_options":"","show_article_options":"","show_urls_images_backend":"","show_urls_images_frontend":""}', 11, 32, '', '